assertions.test_pseudocode:
const html = fs.readFileSync('docs/index.html', 'utf8');
const overviewSlice = html.split('<div class="tab-content" id="evaluate">')[0];
const vl = overviewSlice.indexOf('<div class="verdict-legend">');
const bn = overviewSlice.indexOf('<div class="breaking-news">');
const toc = overviewSlice.indexOf('<nav class="toc">');
assert(vl > -1 && bn > -1 && toc > -1, 'Overview must contain verdict-legend, breaking-news, and nav.toc');
assert(vl < bn && bn < toc, 'breaking-news must appear between verdict-legend and nav.toc on Overview');

const bnBlock = html.match(/<div class="breaking-news">[\s\S]*?<\/div>\s*\n\s*<\/div>/)[0];
const items = (bnBlock.match(/<div class="bn-item">/g) || []).length;
assert(items === 3, 'breaking-news must retain exactly 3 bn-item entries');
assert(bnBlock.includes('#ts-april-2026-update'), 'bn-item #1 timestamp-tab link preserved');
assert(bnBlock.includes('#section-1-8'), 'bn-item #2 refraction section link preserved');
assert(bnBlock.includes('#pred-mined'), 'bn-item #3 predictions catalog link preserved');

const css = fs.readFileSync('build-scripts/generate-html.js', 'utf8');
const bnRuleMatch = css.match(/\.breaking-news\{[^}]+\}/);
assert(bnRuleMatch, '.breaking-news rule present');
const bnRule = bnRuleMatch[0];
assert(bnRule.includes('border:1px'), '.breaking-news must use 1px border (was 2px)');
assert(!bnRule.includes('linear-gradient'), '.breaking-news must not use linear-gradient background (pre-A7 chrome)');
assert(!bnRule.includes('var(--accent)'), '.breaking-news must not use accent color in chrome');
const bhMatch = css.match(/\.bn-header\{[^}]+\}/);
assert(bhMatch, '.bn-header rule present');
assert(bhMatch[0].includes('text-transform:uppercase'), '.bn-header must be uppercase eyebrow');
assert(bhMatch[0].includes('letter-spacing'), '.bn-header must have letter-spacing (eyebrow type role)');
assert(!bhMatch[0].includes('color:var(--accent)'), '.bn-header must not use accent color (pre-A7 hero weight)');

const bnHeader = html.match(/<h2 class="bn-header">[^<]*<\/h2>/);
assert(bnHeader, '<h2 class="bn-header"> present');
assert(!bnHeader[0].includes('&#128240;'), '.bn-header must not contain 📰 newspaper emoji (pre-A7 chrome)');
assert(bnHeader[0].includes('Latest Findings'), '.bn-header must retain "Latest Findings" text');
